  ('sp_012', 'service_pressure', 'Varför ska man aldrig springa i restaurangen, även under rush?', ARRAY['Det ser oprofessionellt ut men är i övrigt ofarligt', 'Löpning ökar risken för olyckor och kollisioner med personal, gäster och utrustning', 'Det stör inte gäster men kan skada matens temperatur', 'Restauranglagen förbjuder det'], 1, 'easy', true),
  ('sp_013', 'service_pressure', 'Hur hanterar du en konflikt med en kollega mitt under ett hektiskt serviceskifte?', ARRAY['Löser det fullt ut direkt, hur lång tid det än tar', 'Ignorerar det helt och hoppas att det går över', 'Hanterar det kort och professionellt och parkerar djupare diskussion till efter service', 'Ber en chef lösa det omedelbart'], 2, 'hard', true),
  ('sp_014', 'service_pressure', 'Vad är "dead time" (dödtid) under ett serviceskifte?', ARRAY['Det sista skiftet på kvällen', 'Lugnare perioder mellan rusningar — perfekt tid att återfylla, städa och förbereda', 'Tid då köket inte kan ta emot beställningar', 'Den del av kvällen då inga dricks ges'], 1, 'medium', true),
  ('sp_015', 'service_pressure', 'Hur meddelar du artigt en gäst att det är lång väntetid?', ARRAY['Undviker ämnet och hoppas de inte frågar', 'Lovar 5 minuter oavsett verkligheten för att hålla dem lugna', 'Informerar ärligt med realistisk tid och ber om ursäkt för besväret', 'Ber dem gå och återkomma senare'], 2, 'medium', true),
  ('sp_016', 'service_pressure', 'Vad är risken med att skynda på desserter under rush?', ARRAY['Inga risker — ju snabbare, desto bättre', 'Gäster känner sig hastade och nöjdheten och dricksen sjunker trots att maten kan ha varit bra', 'Desserter smakar sämre när de serveras snabbt', 'Kocken hinner inte göra desserterna med samma kvalitet'], 1, 'medium', true),
  ('sp_017', 'service_pressure', 'Vad bör en chef göra för att stötta personalen under rush?', ARRAY['Sitta på kontoret och övervaka via kameror', 'Vara synlig på golvet, ta bort hinder och hjälpa till praktiskt där det behövs mest', 'Ständigt ge verbal feedback om vad som kan förbättras', 'Schemalägga extrapersonal dag för dag'], 1, 'medium', true),
  ('sp_018', 'service_pressure', 'Vad är "grace under pressure" i restaurangsammanhang?', ARRAY['Att ha snabb framfart i salen', 'Att behålla professionalism, lugn och vänlighet mot gäster även när allt går fel internt', 'Att servera rätt rätt med rätt hand', 'Att erbjuda gratis mat vid förseningar'], 1, 'medium', true),
  ('sp_019', 'service_pressure', 'Vad är den bästa strategin när allting verkar gå fel samtidigt?', ARRAY['Panik är naturligt — låt den komma och gå', 'Andas, kommunicera tydligt med teamet och prioritera en sak i taget', 'Låt chefen ta över allt omedelbart', 'Ta en paus och kom tillbaka fräschare'], 1, 'hard', true),
  ('sp_020', 'service_pressure', 'Vad är "verbal shorthand" i köket och varför är det viktigt under tryck?', ARRAY['Att skriva korta notor istället för att prata', 'Korta, standardiserade kommunikationsfraser (t.ex. "behind", "fire", "86") som sparar tid och undviker missförstånd', 'Att inte prata alls — tyst kök är ett gott kök', 'Att använda förkortningar i beställningssystemet'], 1, 'hard', true),
  ('sp_021', 'service_pressure', 'Varför är andningsteknik och medveten stress-hantering relevant för restauranganställda?', ARRAY['Det är inte relevant i restaurangbranschen', 'Kontrollerad andning sänker stressnivån, förbättrar beslutsfattande och hjälper att behålla lugnet mot gäster', 'Det är ett krav i kockutbildningen', 'Det hjälper enbart i köket, inte i salen'], 1, 'medium', true),
  ('sp_022', 'service_pressure', 'Vad gör du om kylskåpet går sönder under ett hett sommarsommardagsskifte?', ARRAY['Väntar och hoppas att det löser sig av sig självt', 'Informerar chef omedelbart, kontrollerar temperaturer och kasserar livsmedel som nått farlig temperatur', 'Fortsätter använda innehållet — det är okej några timmar till', 'Stänger restaurangen direkt'], 1, 'medium', true),
  ('sp_023', 'service_pressure', 'Vad är "bordsomsättning" (table turning) under högtrycksservice?', ARRAY['Att rotera borden i restaurangen för bättre flöde', 'Att effektivt frigöra och duka om bord för att ta in nästa gäst', 'Att flytta gäster till ett annat bord', 'Att ta in fler gäster än restaurangen egentligen klarar'], 1, 'medium', true),
  ('sp_024', 'service_pressure', 'Vad innebär "att hålla sin bana" (staying in your lane) under högtryck?', ARRAY['Att röra sig längs väggen för att inte störa gäster', 'Att fokusera på sin tilldelade roll utan att gå in i kollegors ansvarsområde utan behov', 'Att inte gå ut i köket under service', 'Att arbeta enbart i salen och aldrig vid kassan'], 1, 'medium', true),
  ('sp_025', 'service_pressure', 'Vad är tecknet på att en restaurang hanterar tryck professionellt?', ARRAY['Att ingen personal pratar med gäster under rush', 'Att gäster knappt märker av stressen — service och kommunikation håller hög standard även under tryck', 'Att alla beställningar tar lika lång tid oavsett belastning', 'Att personalen alltid ser stressad ut så gäster förstår situationen'], 1, 'hard', true)
